3. Bei den folgenden Spielen streben beide Spieler das Nash-Gleichgewicht "oben links" an. Prüfen Sie, wie hoch die Wahrscheinlichkeit für Spieler 1, versehentlich "unten" zu spielen ($p_u$), sein darf, damit für Spieler 2 "links" noch die richtige Strategie ist. Prüfen Sie auch, wie hoch die Wahrscheinlichkeit für Spieler 2 sein darf, versehentlich rechts ($p_r$) zu spielen, sodass für Spieler 1 "oben" noch die richtige Strategie ist. 

::: {#ffb65408 .cell message='false' execution_count=3}
``` {.python .cell-code}
# Python

import numpy as np
import random
import pandas as pd

from lets_plot import *
from IPython.display import display, HTML

LetsPlot.setup_html()


def create_plot(a, A, b, B, c, C, d, D, Spiel):
    LetsPlot.setup_html()
    return (
        ggplot() +
        geom_text(x=-0.5, y=2, label=a) +
        geom_text(x=-1.5, y=0.75, label=A) +
        geom_text(x=-0.5, y=-1, label=b) +
        geom_text(x=-1.5, y=-2.25, label=B) +
        geom_text(x=1.5, y=2, label=c) +
        geom_text(x=0.5, y=0.75, label=C) +
        geom_text(x=1.5, y=-1, label=d) +
        geom_text(x=0.5, y=-2.25, label=D) +
        geom_text(x=-1, y=3.3, label='links') +
        geom_text(x=1, y=3.3, label='rechts') +
        geom_text(x=-2.2, y=1.375, angle=90, label='oben') +
        geom_text(x=-2.2, y=-1.625, angle=90, label='unten') +
        geom_text(x=0 , y=4 , fontface="bold", label='Spieler 2') +
        geom_text(x=-2.7 , y=0 , angle=90 , fontface="bold", label='Spieler 1') +
        geom_segment(x=-2, xend=2, y=0, yend=0) +
        geom_segment(x=-2, xend=2, y=3, yend=3) +
        geom_segment(x=-2, xend=2, y=-3, yend=-3) +
        geom_segment(x=-2, xend=-2, y=-3, yend=3) +
        geom_segment(x=0 , xend=0 , y=-3 , yend=3) +
        geom_segment(x=2 , xend=2 , y=-3 , yend=3) +
        theme_void() +
        labs(title=f'Auszahlungen Spiel {Spiel}')
        )

myseed = 100
Spiel = 0
results = []

for i in range(10):
    myseed = myseed + 1
    Spiel = Spiel + 1
    random.seed(myseed)  # Optional für Reproduzierbarkeit


    while True:
      A = random.randint(0, 9)
      a = random.randint(0, 9)
      B = A-random.choice([1, 2, 3])
      b = random.randint(0, 9)
      C = random.choice([-10, -12, -30])
      c = a-random.choice([1, 2])
      D = random.randint(0, 9)
      d = random.randint(0, 9)

      # Bedingungen prüfen
      cond1 = (A > B) and (a >= c) # NGG ol
      cond2 = (D  > C) and (d > b) and (A > D) and (a > d)

      # Wenn beide Bedingung erfüllt ist, Schleife beenden
      if  (cond1 and cond2):
        break


    p = create_plot(a, A, b, B, c, C, d, D, Spiel)

    display(p)

    p_r = (A-B)/(A-B-C+D)
    p_u = (a-c)/(a-b-c+d)

    # print(f"p_r={p_r}")
    # print(f"p_u={p_u}")

    results.append({
        'Spiel': Spiel,
        'p_u': round(p_u, 3) if p_r is not None else None,
        'p_r': round(p_r, 3) if p_u is not None else None
    })

results_df = pd.DataFrame(results)

#results_df
